<template><view class="page"><view class="title">幼儿内容库</view><picker :range="categories" @change="choose"><view class="input">分类：{{selected||'全部'}}</view></picker><AppCard v-for="x in items" :key="x.id" :title="x.title"><view>{{x.type}} · {{x.category}}</view></AppCard></view></template><script setup lang="ts">import{ref}from'vue';import{onShow}from'@dcloudio/uni-app';import AppCard from'@/components/AppCard.vue';import{qingxierApi}from'@/services/api';const categories=ref<string[]>([]),selected=ref(''),items=ref<any[]>([]);async function load(){const c=await qingxierApi.kidsCategories();categories.value=c.map(x=>x.name);items.value=await qingxierApi.kidsContent(selected.value)}onShow(load);async function choose(e:any){selected.value=categories.value[Number(e.detail.value)];await load()}</script>
